-- Enrichment marathon batch: Permify, Permit.io, Perplexity, Persado, PersistIQ, Personio, Phorge, PhotoPrism

-- ── Permify ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Permify is an open-source, Google Zanzibar-inspired authorization engine that lets engineering teams centralize fine-grained permission logic (RBAC, ABAC and ReBAC) outside application code. The project was acquired by FusionAuth in November 2025 and now ships as part of FusionAuth's identity stack.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted Community Edition)$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$11-50 employees (pre-acquisition team, now part of FusionAuth)$q$, company_size),
  headquarters = COALESCE($q$Westminster, Colorado, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Permify Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Permify is an open-source Zanzibar-style authorization engine now part of FusionAuth. See features, self-hosting pricing, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Permify is an open-source authorization service built around the ideas in Google's Zanzibar paper, the system Google uses to manage access control for products like Drive, YouTube and Google Cloud. Rather than hard-coding permission checks into application logic, engineering teams model roles, relationships and attributes in a dedicated Permify schema and query a centralized service for real-time access decisions, supporting role-based access control (RBAC), attribute-based access control (ABAC) and relationship-based access control (ReBAC) in one unified policy language. Founded in 2022, Permify grew into a widely adopted open-source project reportedly used by both startups and Fortune 100 companies, processing billions of authorization checks per day across dozens of production deployments before being acquired by identity platform FusionAuth in November 2025. The core Community Edition remains free and open source under the AGPL-3.0 license, and can be self-hosted indefinitely via Docker or Kubernetes with no seat or usage fees; teams that want a managed option can instead use the hosted Permify Cloud service, which historically added backups, high availability and enterprise support. Following the FusionAuth acquisition, commercial and enterprise pricing for Permify now runs through FusionAuth's plans, combining Permify's authorization layer with FusionAuth's authentication and customer identity platform into what the two companies describe as a complete, self-hostable stack for both authentication and authorization. Permify's target users are software engineering, platform and security teams, particularly at B2B SaaS, fintech and enterprise software companies, that have outgrown hard-coded if-else permission checks or simple database role columns and need centralized, auditable, low-latency authorization as their tenancy and permission models grow more complex. Its closest direct competitor is Permit.io, another Zanzibar-inspired authorization platform, though Permit.io is commercial and hosted-first with a low-code policy editor, while Permify leans more heavily into being open source and self-hosted first. Other alternatives include Oso, a policy engine and authorization library; Auth0 FGA and its open-source counterpart OpenFGA, Okta's own Zanzibar-inspired project; and AWS Verified Permissions, Amazon's managed authorization service. Because Permify is developer infrastructure rather than a business tool, its buyers are typically platform engineers, backend developers and security engineers rather than non-technical stakeholders.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b95ba4cb-96d7-4478-9722-2807aa591486';

