-- ── Perplexity ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Perplexity is an AI-powered answer engine that pairs large language models with real-time web search to deliver conversational, cited answers, alongside an agentic browser (Comet) and enterprise search offerings.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free; Pro $20/month$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE($q$Approximately 1,400 employees (as of mid-2026)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Perplexity Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Perplexity is an AI answer engine with real-time web search and citations. Compare Free, Pro and Max pricing, features and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Perplexity is an AI-powered answer engine, often described as a challenger to traditional search engines, founded in 2022 by Aravind Srinivas (CEO), Denis Yarats, Johnny Ho and Andy Konwinski, several of them former researchers at organizations including OpenAI, DeepMind and Databricks. Headquartered in San Francisco, Perplexity combines large language models with real-time web retrieval to generate conversational, source-cited answers rather than a plain list of links, and has expanded into an agentic browser called Comet, a Sonar developer API, and enterprise search and deep-research products. The company has raised more than $1.7 billion across multiple funding rounds from investors including Nvidia, SoftBank and Jeff Bezos, reaching a valuation reported around $20 to $22 billion in early 2026, making it one of the most highly valued AI startups outside the major foundation-model labs themselves. Perplexity's pricing is freemium: the Free plan offers a limited number of daily Pro searches using its default model; Perplexity Pro costs $20 per month, or $200 per year, and unlocks unlimited quick searches, access to multiple underlying models from providers such as OpenAI, Anthropic and Google, file uploads and image generation; Perplexity Max costs $200 per month and adds access to Perplexity's most advanced reasoning models, extended use of Comet's agentic browsing features, and priority access to new capabilities; and Enterprise plans, Enterprise Pro and Enterprise Max, are priced per seat, from roughly $40 to $325 per seat per month, adding SSO, SCIM, audit logs and higher usage limits for organizations. Perplexity's key differentiator versus traditional search is that it functions as an answer engine: rather than returning ranked links, it synthesizes a direct answer with inline citations to sources, positioning it as a challenger to Google Search as well as to conversational AI products like ChatGPT and Microsoft Copilot. Target users span individual knowledge workers, researchers and students on the free or Pro tiers, through professionals and enterprises purchasing Max or Enterprise plans for higher-volume research and agentic workflows. Named competitors include Google, both classic Search and its Gemini-powered AI Overviews, OpenAI's ChatGPT including its search features, Microsoft Copilot, and You.com, another AI-native search startup.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fca1586c-759c-47c3-b289-f752d876f509';

