-- ── PersistIQ ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PersistIQ is a sales engagement platform that helps small sales teams automate personalized email outreach, calling and follow-up sequences, owned by Wishpond Technologies since 2021.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$59/user/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$11-50 employees (subsidiary of Wishpond Technologies)$q$, company_size),
  headquarters = COALESCE($q$San Mateo, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PersistIQ Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PersistIQ is a sales engagement platform for small teams. Compare features, Essentials and Premium pricing, and top alternatives for 2026.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PersistIQ is a sales engagement platform founded in 2014 and based in San Mateo, California, built specifically for small sales teams that need to automate outbound prospecting without the complexity or cost of enterprise sales-engagement suites. The platform lets users build multi-step, personalized outreach sequences that combine automated email, LinkedIn touches, calling and task reminders, track opens, clicks and replies, and run A/B tests on messaging, all from a single inbox-style workspace. In March 2021, PersistIQ was acquired by Wishpond Technologies Ltd., a Vancouver-based, publicly traded marketing software company, for approximately US$3 million; PersistIQ has continued to operate as a standalone product and brand under Wishpond's ownership, serving more than 900 customers around the time of acquisition. PersistIQ's pricing is subscription-based and per user: the Essentials plan starts at $59 per user per month billed annually, or $75 per user per month billed monthly, and includes unlimited prospects and campaigns with roughly 300 emails sent per day; the Premium plan runs about $99 per user per month billed annually, or around $120 per user per month billed monthly, and raises the daily email limit to around 600 while adding Salesforce integration, a built-in phone dialer with call recording, and live onboarding support; a Teams plan is also available for growing sales organizations. PersistIQ does not offer an ongoing free plan but provides a 14-day free trial. The platform targets small and mid-sized B2B sales teams, sales development representatives and founder-led sales motions at startups that want an easy-to-set-up outreach tool rather than a heavyweight revenue platform requiring dedicated sales-ops administration. Its most direct competitors are Outreach and Salesloft, both larger, enterprise-oriented sales engagement platforms, as well as Mailshake and Woodpecker.co, which similarly target smaller teams with simpler, email-centric outbound workflows; PersistIQ differentiates itself with a lower price point, faster setup, and a feature set intentionally scoped to what small sales teams need rather than the broader revenue-intelligence and forecasting capabilities of larger platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2';

