-- ── Phorge ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Phorge is a free, open-source suite of software development collaboration tools, maintained as a community fork of the discontinued Phabricator project, covering code review, task tracking and project wikis.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Not applicable (volunteer-run open-source community project)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (distributed open-source community)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Phorge Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Phorge is a free, open-source Phabricator fork for code review, task tracking and wikis. See features, self-hosting details and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Phorge is a free and open-source software development collaboration suite, best understood as a community-maintained continuation of Phabricator, the project-management and code-review toolkit originally built inside Facebook and later open-sourced before being declared unmaintained by its original maintainer in June 2021. When Phabricator's future became uncertain, a group of community contributors forked the codebase to create Phorge, publishing an initial release that carried over all of Phabricator's existing functionality and has since actively developed the project, reporting hundreds of commits since the fork compared to only a handful on the original, now largely dormant Phabricator repository. Phorge is released under the Apache 2.0 license, the same license Phabricator used, and is entirely free to self-host; there is no paid or hosted commercial tier, and the project is run by volunteer maintainers rather than a company, with its central hub at we.phorge.it hosting documentation, a changelog, and notes from biweekly community planning meetings. Functionally, Phorge provides a suite of applications for software teams: Differential for code review, Diffusion for repository browsing across Git, Subversion and Mercurial, Maniphest for issue and task tracking, Phriction for team wikis, and additional tools for project planning, all under one self-hosted deployment. Because it is entirely community-run, Phorge has no founding company, headquarters, funding round or venture-backed history in the traditional sense; it is governed by an open, rotating group of core contributors known as the Phorge Team. Its target users are engineering teams and open-source projects that were already using Phabricator and needed a maintained successor, as well as organizations that want a free, self-hosted, all-in-one alternative to hosted SaaS developer tools. Because Phorge duplicates much of what commercial platforms offer, it competes indirectly with GitLab, available self-hosted or as SaaS with code review plus CI/CD, Gitea and Forgejo, lightweight self-hosted Git platforms, and Redmine, an open-source project and issue tracker, as well as hosted tools like GitHub and Atlassian's Jira for teams that eventually outgrow it, though none of these are drop-in replacements for the specific Differential-based code review workflow that Phorge preserves from Phabricator.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085';

