-- ── PhotoPrism ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$PhotoPrism is a self-funded, open-source, AI-powered photo and video management app that you self-host to organize, tag and search your personal media library privately.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted Community Edition); paid memberships from about EUR2/month$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$PhotoPrism Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$PhotoPrism is a self-hosted, open-source AI photo manager. Compare free and paid Essentials/Plus pricing, features and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$PhotoPrism is a self-hosted, open-source photo and video management application founded in 2018 by Michael Mayer and Theresa Gresch and based in Berlin, Germany, built for people who want Google-Photos-style AI organization, such as automatic tagging, face recognition, duplicate detection and a searchable world map of where photos were taken, without uploading their personal media to a third-party cloud service. The company behind it, PhotoPrism UG, is 100 percent self-funded and has taken no outside venture capital, with a small team, reported around three people as of 2026, which the founders present as core to their promise never to sell user data and to remain transparent about how the software works. The core PhotoPrism Community Edition is free and open source, licensed under the AGPLv3, and can be self-hosted via Docker on anything from a Raspberry Pi to a home server or cloud VPS, giving users unlimited storage limited only by their own hardware. For users who want extra functionality, PhotoPrism sells optional paid memberships on top of the same self-hosted software: an Essentials membership priced around EUR2 per month self-hosted, or roughly EUR200 per month for a managed or hosted version, adds features like additional user roles and enhanced maps, while a Plus membership priced around EUR6 per month self-hosted, or roughly EUR600 per month managed, adds a full user-management UI, integrations with AI backends like Ollama and OpenAI, single sign-on via OpenID Connect, and hardened security options; both memberships are billed annually. Third-party hosts such as PikaPods also offer fully managed PhotoPrism instances starting around $6.50 per month for users who don't want to self-host at all. PhotoPrism's target users are privacy-conscious individuals, families, photographers and small organizations who want AI-powered photo search and organization while keeping full ownership and control of their media library. Its closest competitors are Immich, another fast-growing open-source, self-hosted photo and video backup app with a more mobile-app-first design, Google Photos and Apple Photos, the dominant cloud-hosted consumer alternatives, and Nextcloud Memories, a photo-management add-on for the broader Nextcloud self-hosted platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2f89cac5-124c-4e1b-8f09-b84e459dd4dc';

