INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Zanzibar-inspired ReBAC engine$q$, $q$Implements a Google Zanzibar-style relationship-based access control model for handling deeply nested permission graphs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Unified RBAC, ABAC and ReBAC schema$q$, $q$Lets teams combine role-based, attribute-based and relationship-based rules in one policy language.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Low-latency access checks$q$, $q$Designed to answer permission check requests in the low milliseconds even at high query volume.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Self-hosted Community Edition$q$, $q$Free, open-source deployment via Docker or Kubernetes with no usage-based licensing fees.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Multi-tenant isolation$q$, $q$Separates authorization data and policies per tenant within a single Permify deployment.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$gRPC and REST APIs$q$, $q$Provides language-agnostic APIs and SDKs for integrating permission checks into any backend stack.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Audit-friendly permission listing$q$, $q$Offers bulk lookup endpoints to list what a user can access or who can access a given resource.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Backed by FusionAuth$q$, $q$Since its November 2025 acquisition, Permify is paired with FusionAuth's authentication and CIAM platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Free, self-hostable open-source core with no per-seat licensing costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Handles complex, deeply nested permission relationships that simple role tables cannot express$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Sub-millisecond to low-millisecond permission check performance at scale$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Backed by FusionAuth's engineering resources and support organization since the 2025 acquisition$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Active open-source community with frequent releases$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$AGPL-3.0 licensing can require legal review for companies embedding Permify in proprietary products$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Steeper learning curve than basic RBAC libraries due to the relationship-based modeling approach$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Public, self-serve pricing became less transparent after the FusionAuth acquisition$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Requires teams to operate and maintain additional infrastructure unless using a managed offering$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Long-term standalone product roadmap is now tied to FusionAuth's strategy$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$What is Permify?$q$, $q$Permify is an open-source authorization service, inspired by Google Zanzibar, that centralizes fine-grained permission logic such as RBAC, ABAC and ReBAC outside of application code.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Is Permify free to use?$q$, $q$Yes. The Permify Community Edition is free and open source under the AGPL-3.0 license and can be self-hosted indefinitely.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Is Permify still an independent company?$q$, $q$No. Permify was acquired by identity platform FusionAuth in November 2025 and now operates as Permify, a FusionAuth company.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$What authorization models does Permify support?$q$, $q$Permify supports role-based access control (RBAC), attribute-based access control (ABAC) and relationship-based access control (ReBAC) in a single schema.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$How is Permify different from Permit.io?$q$, $q$Both are Zanzibar-inspired authorization platforms, but Permify is open source and self-hosting first, while Permit.io is a commercial, hosted-first platform with a low-code policy UI and a free managed tier.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Can Permify replace OpenFGA or Auth0 FGA?$q$, $q$Permify is a comparable alternative to OpenFGA and Auth0 FGA, since all three are open-source, Zanzibar-inspired authorization engines with similar relationship-based modeling approaches.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Does Permify require rewriting an existing application?$q$, $q$No. Permify is typically integrated incrementally by replacing existing permission checks with calls to the Permify API rather than requiring a full rewrite.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$What license does Permify use?$q$, $q$The Permify Community Edition is released under the AGPL-3.0 open-source license.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Multi-tenant SaaS permissions$q$, $q$B2B SaaS platforms use Permify to manage per-tenant roles and permissions, so each customer organization can define its own access rules without custom code.$q$, $q$Platform and backend engineering teams at B2B SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Fine-grained document and resource sharing$q$, $q$Teams building Google-Drive-like sharing features use Permify's ReBAC model to represent nested folder, workspace and delegated-access permissions.$q$, $q$Engineering teams building collaboration or content-sharing products$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Centralized compliance and audit trails$q$, $q$Security and compliance teams use Permify's permission-listing APIs to audit who has access to what across an application, supporting regulatory reviews.$q$, $q$Security and compliance teams at regulated software companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Community Edition$q$, $q$Free$q$, $q$N/A (self-hosted)$q$, NULL, $q$["Open-source, AGPL-3.0 licensed","Self-hosted via Docker or Kubernetes","RBAC, ABAC and ReBAC support","Community support channels"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$Managed / Enterprise (via FusionAuth)$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["SLA-backed managed hosting","Backups and high availability","Enterprise support","Bundled with FusionAuth authentication platform"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Permify is an open-source authorization service built around the ideas in Google's Zanzibar paper, the system Google uses to manage access control for products like Drive, YouTube and Google Cloud. Rather than hard-coding permission checks into application logic, engineering teams model roles, relationships and attributes in a dedicated Permify schema and query a centralized service for real-time access decisions.$q$, $q$Founded in 2022, Permify grew into a widely adopted open-source project used by both startups and Fortune 100 companies before being acquired by identity platform FusionAuth in November 2025. The core Community Edition remains free, open source under the AGPL-3.0 license, and self-hostable via Docker or Kubernetes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Permify's core strength is its support for role-based (RBAC), attribute-based (ABAC) and relationship-based (ReBAC) access control through a single unified policy language. This lets teams express complex permission graphs, such as nested organizations, shared folders or delegated admin rights, that traditional role tables struggle to represent.$q$, $q$The service exposes gRPC and REST APIs for permission checks, bulk permission listing, and access-control-list lookups, with response times designed to stay in the low milliseconds even at large scale. Multi-tenancy support lets a single Permify deployment isolate authorization data and policies per customer or business unit.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Permify's Community Edition is free and open source, and teams can self-host it indefinitely with no seat or usage fees beyond their own infrastructure costs. For teams that prefer a managed option, Permify previously offered Permify Cloud, a hosted, SLA-backed service with backups and enterprise support.$q$, $q$Following the November 2025 acquisition by FusionAuth, managed and enterprise pricing for Permify is now handled through FusionAuth's commercial plans, so organizations evaluating paid options should contact FusionAuth sales directly for current quotes.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b95ba4cb-96d7-4478-9722-2807aa591486', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Low-code policy editor$q$, $q$Visual interface for defining RBAC, ABAC, ReBAC and PBAC policies without writing policy code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Embeddable permission UI components$q$, $q$Ready-made UI elements for building user- and role-management screens into customer-facing apps.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$GitOps policy pipelines$q$, $q$Syncs authorization policies through Git-based CI/CD workflows for version control and review.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Policy decision point (PDP)$q$, $q$Lightweight, embeddable enforcement layer for low-latency access checks close to the application.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Multi-tenancy support$q$, $q$Manages isolated roles, tenants and permissions for multiple customer organizations from one account.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Audit and decision logs$q$, $q$Extendable logs of every access decision for compliance and debugging.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$SSO and SOC 2 Type II$q$, $q$Optional single sign-on and SOC 2 Type II certification on paid tiers for enterprise security requirements.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$AI agent authorization$q$, $q$Supports authorizing AI agent and tool actions for teams building AI-powered applications.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Generous free tier (1,000 monthly active users with full feature access)$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Visual, low-code policy editor lowers the barrier to implementing fine-grained access control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Supports RBAC, ABAC, ReBAC and PBAC models in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Ready-made embeddable UI components speed up building permission-management screens$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$GitOps workflow fits naturally into existing CI/CD pipelines$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Hosted-first architecture means less control than a fully self-hosted, open-source alternative$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Costs can scale quickly as monthly active users and tenants grow beyond the free and Startup tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Enterprise features like HIPAA and GDPR compliance support and multi-cloud deployment require custom Enterprise pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Smaller company (reported around 14-25 employees) than some enterprise-focused competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Advanced compliance certifications such as SOC 2 Type II are gated behind the paid Pro tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$What is Permit.io?$q$, $q$Permit.io is a full-stack authorization-as-a-service platform that gives developers a hosted policy engine, UI components and SDKs for RBAC, ABAC, ReBAC and PBAC access control.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Is Permit.io free?$q$, $q$Yes, Permit.io offers a free Community tier for up to 1,000 monthly active users with full feature access.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Who founded Permit.io?$q$, $q$Permit.io was founded in 2021 in Tel Aviv, Israel by Or Weis and Asaf Cohen.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$How does Permit.io pricing work?$q$, $q$Pricing scales with monthly active users, tenants and environments, moving from a free Community tier through Startup, Pro and custom Enterprise tiers.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$What is the difference between Permit.io and Permify?$q$, $q$Permit.io is a hosted, low-code platform, while Permify is an open-source, self-hosted-first authorization engine; both are inspired by Google Zanzibar.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Does Permit.io support AI agent authorization?$q$, $q$Yes, Permit.io markets specific support for authorizing AI agent and tool actions in AI-powered applications.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Can Permit.io be self-hosted?$q$, $q$Permit.io is primarily a hosted service, though its policy decision point can run embedded at the edge close to the application.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$What compliance certifications does Permit.io offer?$q$, $q$SOC 2 Type II is available on the Pro tier, with HIPAA, GDPR and CCPA compliance support available on the Enterprise tier.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Startup and scale-up access control$q$, $q$Early-stage engineering teams use Permit.io's free and Startup tiers to stand up fine-grained permissions quickly without building an in-house system.$q$, $q$Startups and scale-up engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$AI agent and tool authorization$q$, $q$Teams building AI products use Permit.io to gate what autonomous agents and tools are allowed to do within an application.$q$, $q$AI application engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Enterprise compliance-driven authorization$q$, $q$Larger organizations use Permit.io's Enterprise tier to meet HIPAA, GDPR and CCPA requirements while deploying across multi-cloud or on-premises environments.$q$, $q$Enterprise security and platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 1,000 monthly active users","20 tenants, 3 environments, 25 roles","Full RBAC, ABAC, ReBAC and PBAC access","Unlimited microservices, basic Slack support","14-day log retention"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Startup$q$, $q$From $5/month$q$, $q$Monthly or yearly (18% discount)$q$, NULL, $q$["Up to 25,000 monthly active users","100 tenants, 5 environments","GitOps CI/CD pipeline","Extendable audit and decision logs"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Pro$q$, $q$From $25/month$q$, $q$Monthly or yearly (18% discount)$q$, NULL, $q$["Up to 50,000 monthly active users","20,000 tenants, 50 environments","Dedicated Slack support","SOC 2 Type II certification, optional SSO","21-day log retention"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Unlimited monthly active users and tenants","Full HIPAA, GDPR and CCPA compliance suite","Multi-cloud or on-premises deployment","Dedicated success representative","Up to 0.9999% SLA option"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Permit.io is a full-stack authorization-as-a-service platform that helps engineering teams implement access control without writing permission logic from scratch. It provides a hosted policy engine, a low-code policy editor, and embeddable UI components for building permission-management screens directly into a product.$q$, $q$Founded in 2021 by Or Weis and Asaf Cohen in Tel Aviv, Israel, Permit.io has raised roughly $14 million across seed and follow-on funding to expand its platform and grow its go-to-market team, with a particular recent focus on authorizing AI agent and tool actions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Permit.io supports RBAC, ABAC, ReBAC and PBAC models from a single dashboard, letting teams mix policy types as their application's access-control needs evolve. Policies can be managed visually or as code and synced through a GitOps CI/CD pipeline for version control and review.$q$, $q$Enforcement happens through a lightweight, embeddable policy decision point designed for low-latency checks, while extendable audit and decision logs give teams visibility into every access decision for debugging and compliance reviews.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d826762-9d50-46fb-93f2-f3db167ecdd7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Permit.io offers a free Community tier covering up to 1,000 monthly active users with full feature access, making it accessible for small projects and early-stage startups. Paid tiers scale by monthly active users, tenants and environments: Startup starts around $5 per month and Pro starts around $25 per month, both billed monthly or yearly with an annual discount.$q$, $q$Enterprise pricing is custom and adds unlimited scale, dedicated support, full compliance coverage (HIPAA, GDPR, CCPA) and multi-cloud or on-premises deployment options for larger organizations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$AI answer engine with citations$q$, $q$Generates direct, conversational answers backed by inline citations to live web sources rather than a list of links.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Multi-model access$q$, $q$Lets Pro and Max subscribers choose between multiple underlying AI models from different providers for a given query.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Comet agentic browser$q$, $q$An AI-powered browser that can complete multi-step tasks like research, form-filling and shopping on a user's behalf.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Perplexity Labs and deep research$q$, $q$Produces longer-form research reports, spreadsheets and visualizations from a single prompt.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Sonar API$q$, $q$A developer-facing search and answer API for building Perplexity's retrieval capabilities into third-party applications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$File and image analysis$q$, $q$Supports uploading documents and images for the AI to analyze alongside web search.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Enterprise admin controls$q$, $q$SSO, SCIM provisioning and audit logs available on Enterprise plans for organizational deployment.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Cited, source-linked answers make it easier to verify AI-generated claims than typical chatbots$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Free tier gives meaningful daily usage without a credit card$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Access to multiple frontier AI models under one subscription on Pro and Max$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Rapidly growing feature set, including the Comet browser and deep research, beyond simple Q and A$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Backed by major investors, suggesting continued investment in product development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Max tier at $200/month is significantly more expensive than many competing AI subscriptions$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Enterprise per-seat pricing, up to $325/seat/month, is costly for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$As a challenger answer engine, indexing depth and freshness can vary versus Google's decades of crawl infrastructure$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Rapid pricing and product changes make it necessary to check current plan details before purchasing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Heavy reliance on external model providers for some features ties quality to third-party model performance$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$What is Perplexity?$q$, $q$Perplexity is an AI-powered answer engine that combines large language models with real-time web search to generate cited, conversational answers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Is Perplexity free?$q$, $q$Yes, Perplexity has a free tier with a limited number of daily Pro searches using its default model.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$How much does Perplexity Pro cost?$q$, $q$Perplexity Pro costs $20 per month or $200 per year.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$What is Perplexity Max?$q$, $q$Perplexity Max is a $200-per-month tier that adds Perplexity's most advanced reasoning models and extended use of the Comet agentic browser.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Who founded Perplexity?$q$, $q$Perplexity was founded in 2022 by Aravind Srinivas, Denis Yarats, Johnny Ho and Andy Konwinski.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$What is Perplexity's valuation?$q$, $q$Perplexity's valuation was reported around $20 to $22 billion in early 2026 following its most recent funding round.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$What is Comet?$q$, $q$Comet is Perplexity's AI agentic browser, designed to complete multi-step web tasks such as research and form-filling automatically.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$How is Perplexity different from ChatGPT?$q$, $q$Perplexity is built primarily as a search and answer engine with live citations to web sources, while ChatGPT is a general-purpose conversational assistant that later added search features.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Research and fact-finding$q$, $q$Individuals use Perplexity to quickly get cited, synthesized answers to research questions instead of manually reviewing multiple search results.$q$, $q$Students, researchers and knowledge workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Competitive and market research$q$, $q$Analysts and marketers use Perplexity's deep research mode to generate structured reports and summaries on markets, competitors and trends.$q$, $q$Analysts, marketers and consultants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Agentic task automation via Comet$q$, $q$Professionals use Perplexity's Comet browser to automate multi-step web tasks such as booking, form-filling and research aggregation.$q$, $q$Professionals seeking AI-driven browsing automation$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Limited daily Pro searches","Default AI model","Basic web search with citations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Pro$q$, $q$$20/month ($200/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited quick searches","Access to multiple frontier AI models","File upload and analysis","Image generation"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Max$q$, $q$$200/month ($2,000/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Access to top-tier reasoning models","Extended Comet agentic browser use","Priority access to new features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Enterprise Pro$q$, $q$$40/seat/month$q$, $q$Per seat, monthly or annual$q$, NULL, $q$["Team collaboration and admin controls","SSO","Higher usage limits"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$Enterprise Max$q$, $q$$325/seat/month$q$, $q$Per seat, monthly or annual$q$, NULL, $q$["All models plus advanced options","Expanded Pro Search, Research and Comet usage","SCIM and audit logs"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Perplexity is an AI-powered answer engine that combines large language models with real-time web search to produce direct, conversational answers backed by cited sources, rather than a traditional list of ranked links. Founded in 2022 and based in San Francisco, the company has grown quickly into one of the best-known challengers to traditional search.$q$, $q$Beyond its core search product, Perplexity has expanded into Comet, an agentic AI browser that can complete multi-step tasks, a Sonar developer API for building on top of its search and retrieval technology, and dedicated Enterprise offerings for organizations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Perplexity's core product generates answers with inline citations so users can verify claims against the original web sources, a key differentiator from typical chatbot interfaces. Pro and Max subscribers can choose between multiple underlying AI models from different providers for a given query.$q$, $q$Additional capabilities include Perplexity Labs and deep research modes that produce longer-form reports, spreadsheets and visualizations from a single prompt, file and image analysis, and the Comet agentic browser for automating multi-step web tasks like research and form-filling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fca1586c-759c-47c3-b289-f752d876f509', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Perplexity offers a free tier with a limited number of daily Pro searches, alongside a Pro plan at $20 per month (or $200 per year) that unlocks unlimited quick searches and access to multiple frontier AI models. A Max plan at $200 per month adds top-tier reasoning models and extended agentic browser usage for professionals who rely on AI search as core work infrastructure.$q$, $q$For organizations, Perplexity offers Enterprise Pro and Enterprise Max plans priced per seat, from roughly $40 to $325 per seat per month, adding admin controls, SSO, SCIM provisioning and audit logs.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Compliance-validated content generation$q$, $q$Produces marketing copy that is automatically checked against more than 20 financial-services regulatory frameworks before publishing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Multi-channel creative generation$q$, $q$Generates on-brand copy for email, direct mail, web, SMS, push and paid social from a single platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Performance prediction and scoring$q$, $q$Scores new and existing creative assets for predicted performance before they are deployed.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Real-time variant selection (Automate)$q$, $q$Delivers the best-performing content variant to each customer in real time via API.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Marketing platform integrations$q$, $q$Connects natively with Salesforce Marketing Cloud, Adobe Campaign and Braze, among others.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Brand voice and tone enforcement$q$, $q$Uses specialized AI models to keep generated copy consistent with a brand's approved voice.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Asset library optimization (Optimize)$q$, $q$Refreshes existing creative libraries without re-triggering full legal and compliance review cycles.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Deep, purpose-built compliance tooling for regulated industries like banking and insurance$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Backed by over a decade of proprietary language-performance data across enterprise campaigns$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Reduces legal and compliance review cycles by validating content against regulatory frameworks up front$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Native integrations with major marketing clouds simplify deployment into existing workflows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Proven enterprise customer base including major banks and financial institutions$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Enterprise-only, quote-based pricing with no self-serve or small-business option$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Undisclosed pricing makes it hard to budget or comparison-shop without a sales conversation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Onboarding, around four weeks, is slower than lightweight, self-serve AI copywriting tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Focused heavily on regulated verticals, which may make it overkill for general marketing content needs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Requires integration work with existing marketing clouds to realize full automation value$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$What does Persado do?$q$, $q$Persado uses AI to generate, test and optimize marketing language for large, regulated enterprises across email, web, SMS, direct mail and social channels.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$How much does Persado cost?$q$, $q$Persado does not publish pricing; it sells through a custom, quote-based enterprise model.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Who is Persado for?$q$, $q$Persado targets large regulated enterprises such as banks, insurers and telecom companies that need compliance-validated marketing content.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$When was Persado founded?$q$, $q$Persado was founded in 2012 and is headquartered in New York City.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$What industries does Persado specialize in?$q$, $q$Persado specializes in financial services, insurance, telecom and other heavily regulated sectors.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$What marketing platforms does Persado integrate with?$q$, $q$Persado integrates with marketing platforms including Salesforce Marketing Cloud, Adobe Campaign and Braze.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$How is Persado different from generic AI copywriting tools?$q$, $q$Persado builds in regulatory compliance validation specific to financial services and insurance, unlike general-purpose AI copywriting tools.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Who are Persado's competitors?$q$, $q$Persado competes with Phrasee (now Jacquard, part of Movable Ink), Seventh Sense, and general AI copywriting tools such as Jasper.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Compliant campaign copy for banks and lenders$q$, $q$Banks and lenders use Persado to generate marketing and lifecycle copy that automatically clears internal legal and compliance requirements.$q$, $q$Marketing teams at banks, credit unions and mortgage lenders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Insurance and wealth management marketing$q$, $q$Insurance and wealth management firms use Persado to produce regulation-aware messaging for policy renewals, cross-sell and acquisition campaigns.$q$, $q$Marketing and compliance teams at insurance and wealth management firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Always-on creative optimization$q$, $q$Enterprise lifecycle marketing teams use Persado's Optimize tools to continuously refresh and score large existing asset libraries.$q$, $q$Enterprise CRM and lifecycle marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Fully managed AI content generation and compliance validation","Multi-channel creative production","Real-time variant automation via API","Dedicated enterprise support team"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$Studio$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Self-service optimization and scoring tools","Asset library refresh without full compliance re-review","Access to Persado's language performance insights"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Persado is an enterprise AI platform that generates and optimizes marketing language for large, regulated organizations. Founded in 2012 and headquartered in New York City, the company built its reputation on machine-learning models that predict which words and phrases will drive the strongest customer response.$q$, $q$Today Persado focuses almost entirely on regulated industries, financial services, insurance and telecom, where every piece of marketing copy typically needs to clear legal and compliance review, and its named clients include major banks such as Bank of America, U.S. Bank and TD Bank.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Persado's platform spans content creation, optimization and automated deployment. Its Create capability generates production-ready copy across email, direct mail, web, SMS and social with compliance validation built in, checking generated content against more than 20 financial-services regulatory frameworks.$q$, $q$Its Optimize capability refreshes and scores existing creative libraries without triggering a full compliance re-review, while Automate delivers real-time content variant selection through API integrations with marketing clouds like Salesforce Marketing Cloud, Adobe Campaign and Braze.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e162b95f-b9ff-4468-a12d-35d5c34b4108', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Persado does not publish pricing publicly and sells exclusively through an enterprise, quote-based sales model. Prospective customers typically start with a demo or portfolio audit, with onboarding for a new enterprise customer taking around four weeks.$q$, $q$The platform is organized into a fully managed Enterprise tier with a dedicated team, and a more self-service Studio tier focused on optimization features, both priced individually based on scope, channels and volume.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Multi-channel outreach sequences$q$, $q$Combines automated email, LinkedIn steps, calling and task reminders into one outbound sequence.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Built-in phone dialer$q$, $q$Lets reps place and record calls directly from PersistIQ on the Premium plan.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Email open, click and reply tracking$q$, $q$Tracks engagement on every sequence step to surface which prospects are responding.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$A/B testing$q$, $q$Tests subject lines and message variants to identify higher-performing outreach copy.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$CRM integrations$q$, $q$Syncs with Salesforce and other CRMs to keep prospect and activity data in sync.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Unlimited prospects and campaigns$q$, $q$Both core plans include unlimited prospect lists and outreach campaigns.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Team performance reporting$q$, $q$Provides visibility into rep-level activity and reply rates for sales managers.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Simple setup aimed specifically at small sales teams rather than enterprise sales-ops$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Unlimited prospects and campaigns on all paid plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Combines email, calling and LinkedIn touches in one sequence builder$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Lower price point than enterprise sales engagement platforms like Outreach or Salesloft$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$14-day free trial available before committing to a paid plan$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$No permanent free plan$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Daily email sending caps, around 300 to 600 per day, may constrain high-volume outbound teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Premium features like the phone dialer and Salesforce integration are locked behind the higher-priced tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Smaller company under Wishpond ownership means a smaller roadmap and integration ecosystem than larger competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Monthly billing carries a notable premium over annual pricing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$What is PersistIQ?$q$, $q$PersistIQ is a sales engagement platform that helps small sales teams automate personalized email, LinkedIn and calling outreach sequences.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$How much does PersistIQ cost?$q$, $q$PersistIQ's Essentials plan starts at $59 per user per month billed annually, and Premium starts at about $99 per user per month billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Does PersistIQ have a free plan?$q$, $q$No, PersistIQ does not offer a permanent free plan, but it does provide a 14-day free trial.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Who owns PersistIQ?$q$, $q$PersistIQ has been owned by Wishpond Technologies Ltd. since the acquisition closed in March 2021.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Does PersistIQ include a phone dialer?$q$, $q$Yes, a built-in phone dialer with call recording is available on the Premium plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$What CRMs does PersistIQ integrate with?$q$, $q$PersistIQ integrates with Salesforce, among other CRM and sales tools.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Who is PersistIQ for?$q$, $q$PersistIQ is designed for small and mid-sized B2B sales teams, sales development representatives, and founder-led sales at startups.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$What are PersistIQ's main competitors?$q$, $q$PersistIQ competes with Outreach, Salesloft, Mailshake and Woodpecker.co.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Outbound prospecting for small SDR teams$q$, $q$Small sales development teams use PersistIQ to run personalized, multi-step outbound campaigns without dedicated sales-ops support.$q$, $q$Small sales teams and sales development representatives$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Founder-led sales outreach at startups$q$, $q$Startup founders and early sales hires use PersistIQ to run their own outbound outreach before hiring a dedicated sales team.$q$, $q$Founders and early sales hires at startups$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Multi-channel follow-up automation$q$, $q$Sales teams use PersistIQ to combine email, LinkedIn and calling touches into a single coordinated follow-up cadence.$q$, $q$Sales teams running multi-channel outbound campaigns$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Essentials$q$, $q$$59/user/month (annual) or $75/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited prospects and campaigns","Around 300 emails per day","Email open, click and reply tracking","A/B testing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Premium$q$, $q$$99/user/month (annual) or about $120/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Around 600 emails per day","Salesforce integration","Built-in phone dialer with call recording","Live onboarding support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$Teams$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Volume pricing for larger sales teams","Team performance reporting","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PersistIQ is a sales engagement platform built for small sales teams that want to automate outbound prospecting without adopting a heavyweight enterprise revenue platform. Founded in 2014 and based in San Mateo, California, the company was acquired by publicly traded marketing software company Wishpond Technologies in March 2021.$q$, $q$Since the acquisition, PersistIQ has continued to operate as a standalone product focused specifically on small B2B sales teams, sales development representatives and founder-led sales motions at startups.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$PersistIQ lets users build multi-step outreach sequences that combine automated email, LinkedIn touches, calling and task reminders, tracking opens, clicks and replies along the way. Built-in A/B testing helps teams identify which subject lines and messages perform best.$q$, $q$The Premium plan adds a built-in phone dialer with call recording and native Salesforce integration, while both core plans include unlimited prospects and campaigns, distinguishing PersistIQ from tools that cap list sizes.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4891f9c-1a2c-4ad0-96e4-9cd56abe94d2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PersistIQ charges per user on a monthly or annual subscription. The Essentials plan starts at $59 per user per month billed annually (or $75 per user per month billed monthly) and includes around 300 emails sent per day, while the Premium plan runs about $99 per user per month billed annually (or around $120 per user per month billed monthly) and raises the daily sending limit to about 600 emails.$q$, $q$There is no permanent free plan, but PersistIQ offers a 14-day free trial, and a Teams plan is available for larger sales organizations that need volume pricing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Core HR administration$q$, $q$Centralizes employee records, contracts and organizational data in one system.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Recruiting and applicant tracking$q$, $q$Manages job postings, candidate pipelines and interview scheduling.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Payroll and compliance$q$, $q$Runs or integrates payroll with built-in compliance for country-specific European labor law.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Time tracking and absence management$q$, $q$Tracks working hours, time off and leave balances against local regulations.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Performance and talent management$q$, $q$Supports goal setting, reviews and talent development workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Onboarding and offboarding workflows$q$, $q$Automates new-hire paperwork, equipment requests and offboarding checklists.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Multi-language, multi-country support$q$, $q$Interface and payroll localization across dozens of European languages and jurisdictions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Reporting and people analytics$q$, $q$Provides HR dashboards and reports on headcount, turnover and other workforce metrics.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Deep localization for European payroll and labor-law compliance across dozens of countries$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$All-in-one platform reduces the need for separate recruiting, HR and payroll point solutions$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Interface available in a wide range of European languages$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Well-funded, established vendor with a large existing customer base of around 12,000 customers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Scales from small businesses up through mid-market and larger organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$No public pricing; requires a sales conversation and custom quote for every deal$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Primarily optimized for European employers, which may limit fit for companies focused outside Europe$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Feature depth in some areas, such as advanced talent management, can lag more specialized point solutions$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Implementation and onboarding can take meaningful time for multi-country payroll setups$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Enterprise-tier features and compliance modules add cost as a company scales past the Essential tier$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$What is Personio?$q$, $q$Personio is an all-in-one HR platform covering recruiting, HR administration, payroll, time tracking and talent management.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$How much does Personio cost?$q$, $q$Personio does not publish pricing; it requires a custom quote based on company size and modules across its Essential, Professional and Enterprise tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Where is Personio based?$q$, $q$Personio is headquartered in Munich, Germany.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$When was Personio founded?$q$, $q$Personio was founded in 2015.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Does Personio handle payroll?$q$, $q$Yes, Personio runs payroll directly in several countries and integrates with local payroll partners elsewhere.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$What languages does Personio support?$q$, $q$Personio's interface is available in English, German, Spanish, French, Italian, Dutch, Swedish, Finnish, Polish and additional languages.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Who is Personio best suited for?$q$, $q$Personio is best suited for small and mid-sized businesses operating across multiple European countries.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$What are Personio's main competitors?$q$, $q$Personio competes with BambooHR, Workday, SAP SuccessFactors and HiBob.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Multi-country European HR compliance$q$, $q$HR teams use Personio to manage employee records and payroll compliance consistently across multiple European jurisdictions.$q$, $q$HR teams at companies operating across multiple EU countries$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Recruiting and onboarding at scale$q$, $q$Talent acquisition teams use Personio to manage job postings, candidate pipelines and structured onboarding as headcount grows.$q$, $q$Talent acquisition teams at growing mid-market companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Consolidating HR, payroll and performance in one system$q$, $q$HR leaders replace multiple disconnected point solutions with Personio's single platform covering the full employee lifecycle.$q$, $q$HR leaders consolidating HR technology stacks$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Essential$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Core HR administration","Basic time and absence tracking","Suited for smaller teams, roughly 10-100 employees"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Professional$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Recruiting and applicant tracking","Performance management","Automation for growing teams, roughly 100-500 employees"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Multi-country payroll and compliance","Advanced reporting and people analytics","Support for large, complex organizations, 500-2,000+ employees"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Personio is an all-in-one HR management platform built to handle the compliance and localization complexity of running HR, recruiting and payroll across multiple European countries. Founded in 2015 in Munich, Germany, it has grown into one of Europe's largest HR technology companies.$q$, $q$The platform serves small and mid-sized businesses, roughly 10 to 2,000 employees, that need a single system rather than stitching together separate recruiting, HR and payroll tools for each country they operate in.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Personio covers the full employee lifecycle: recruiting and applicant tracking, onboarding, core HR record-keeping, time tracking and absence management, performance and talent management, and payroll, run directly in several countries or through local partners elsewhere.$q$, $q$The platform's interface is available in more than a dozen languages, and its payroll and compliance tooling is built specifically to handle country-by-country labor law differences across the European markets it primarily serves.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ed578b8-4db9-4fce-98af-7a24c8e0021c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Personio does not publish list pricing and instead sells through a custom, quote-based model organized around Essential, Professional and Enterprise editions that scale with company size and the number of modules a customer needs.$q$, $q$Independent market estimates place core HRIS pricing in the range of roughly EUR5 to EUR15 per employee per month depending on modules and contract length, with volume discounts typically available for larger deals and longer contract terms.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Differential code review$q$, $q$Provides a structured, revision-based code review workflow inherited from Phabricator.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Diffusion repository browsing$q$, $q$Browses and manages Git, Subversion and Mercurial repositories from a unified web UI.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Maniphest task tracking$q$, $q$Tracks issues, bugs and project tasks with customizable workflows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Phriction team wikis$q$, $q$Built-in wiki application for team documentation and knowledge sharing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Self-hosted deployment$q$, $q$Runs entirely on infrastructure the user controls, with no mandatory external service.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Free and open source$q$, $q$Released under the Apache 2.0 license with no licensing fees.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Active community development$q$, $q$Maintained by volunteer contributors with regular releases and public planning meetings.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Completely free, open-source and self-hosted with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Preserves the Differential code-review workflow that many former Phabricator users relied on$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Actively maintained by a volunteer community after Phabricator itself was discontinued$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$All-in-one suite, code review, tasks, wikis and repository browsing, avoids stitching together multiple tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Apache 2.0 license permits broad commercial and non-commercial use$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$No official managed or hosted offering or commercial support contract, since it is entirely volunteer-run$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Smaller contributor base and slower feature velocity than well-funded commercial developer tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Dated user interface and workflows compared to modern SaaS alternatives like GitLab or GitHub$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Requires self-hosting expertise, server setup, upgrades and backups, with no vendor to fall back on$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Migration tooling from Phabricator, while present, still requires manual effort$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$What is Phorge?$q$, $q$Phorge is an open-source fork of Phabricator that provides code review, repository browsing, task tracking and team wikis in one self-hosted suite.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Is Phorge free?$q$, $q$Yes, Phorge is entirely free and open source with no paid tiers.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Why was Phorge created?$q$, $q$Phorge was created after Phabricator was declared unmaintained by its original maintainer in June 2021, prompting community contributors to fork the project.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$What license does Phorge use?$q$, $q$Phorge is released under the Apache 2.0 open-source license.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Can I migrate from Phabricator to Phorge?$q$, $q$Yes, Phorge provides documented update paths for teams migrating from existing Phabricator installations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Does Phorge offer hosted or cloud plans?$q$, $q$No, Phorge is self-hosted only; there is no official commercial hosting offered by the project.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$What version control systems does Phorge support?$q$, $q$Phorge supports Git, Subversion and Mercurial.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Who maintains Phorge?$q$, $q$Phorge is maintained by a volunteer, community-driven group of contributors known as the Phorge Team rather than a company.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Migrating existing Phabricator installs$q$, $q$Teams already running Phabricator use Phorge as a maintained, drop-in successor with documented migration paths.$q$, $q$Teams already using Phabricator needing a maintained successor$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Self-hosted code review for privacy-conscious teams$q$, $q$Engineering teams that require on-premises tooling use Phorge to keep code review and project data entirely under their own control.$q$, $q$Engineering teams that require on-premises tooling$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$All-in-one project collaboration for open-source projects$q$, $q$Open-source maintainers use Phorge's bundled code review, task tracking and wiki tools instead of assembling several separate services.$q$, $q$Open-source project maintainers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$Community (self-hosted)$q$, $q$Free$q$, $q$N/A (self-hosted)$q$, NULL, $q$["Open-source, Apache 2.0 licensed","Full Differential, Diffusion, Maniphest and Phriction applications","Community support via chat and forums","No user or seat limits"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Phorge is a free, open-source software development collaboration suite created as a community fork of Phabricator after Phabricator's original maintainer declared the project unmaintained in June 2021. It preserves Phabricator's full feature set while continuing active development under a volunteer-run community.$q$, $q$Unlike commercial developer tools, Phorge has no company, funding or headquarters behind it; it is maintained by a rotating group of open-source contributors who coordinate publicly through the project's we.phorge.it hub, including a public changelog and biweekly planning meeting notes.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Phorge bundles several applications for software teams into one self-hosted deployment: Differential for structured code review, Diffusion for browsing Git, Subversion and Mercurial repositories, Maniphest for issue and task tracking, and Phriction for team wikis and documentation.$q$, $q$Because the entire suite is self-hosted and open source, teams retain full control over their data and infrastructure, and the project has continued to ship active development, including migration paths for teams moving from legacy Phabricator installations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Phorge is entirely free and open source under the Apache 2.0 license, with no paid tiers, seat limits or commercial hosting offered directly by the project. Any hosting cost comes from the infrastructure a team chooses to run it on.$q$, $q$Because there is no company behind Phorge, there is no official enterprise support contract; teams that need guaranteed support typically rely on community channels or third-party consultants familiar with the Phabricator and Phorge codebase.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aa4f4092-fd7c-44e6-a8d5-8c7d5fc2b085', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$AI-powered tagging and search$q$, $q$Automatically labels and indexes photos so they can be found by content, not just filenames.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Face recognition$q$, $q$Detects and groups faces across a photo library for people-based browsing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Duplicate detection$q$, $q$Identifies and helps remove duplicate or near-duplicate images.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Interactive world map$q$, $q$Plots geotagged photos on a map to browse a library by location.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Self-hosted via Docker$q$, $q$Deploys on personal hardware or any Docker-compatible host for full data ownership.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Open-source core$q$, $q$Community Edition is free and licensed under AGPLv3.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Optional AI backend integrations$q$, $q$Plus membership connects to Ollama and OpenAI for enhanced AI features.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$SSO and hardened security (Plus)$q$, $q$OpenID Connect single sign-on and advanced security hardening on the paid Plus tier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Fully open-source core that is free to self-host indefinitely$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$No third-party cloud upload required, giving users complete control over their photo data$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$100 percent self-funded, independent company with no ad-driven or data-selling business model$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$AI features, face recognition, tagging and duplicate detection, rival mainstream cloud photo apps$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Optional paid memberships are affordable and add clearly scoped extra functionality$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Requires self-hosting knowledge, Docker, storage and backups, unless using a managed provider$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Small team, reported around three people, means slower feature velocity than large commercial competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Some advanced features, such as SSO, the user management UI and AI backend integrations, are locked behind paid memberships$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Managed or hosted pricing, roughly EUR200 to EUR600 per month, is significantly more expensive than self-hosting$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Mobile app experience is generally considered less polished than competitors like Immich$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$What is PhotoPrism?$q$, $q$PhotoPrism is an open-source, self-hosted AI photo and video management application.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Is PhotoPrism free?$q$, $q$Yes, the Community Edition is free and open source; paid memberships add extra features on top.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$How much do PhotoPrism memberships cost?$q$, $q$Essentials starts at about EUR2 per month self-hosted, and Plus starts at about EUR6 per month self-hosted, both billed annually.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Who makes PhotoPrism?$q$, $q$PhotoPrism is made by PhotoPrism UG, a self-funded company founded by Michael Mayer and Theresa Gresch in Berlin, Germany.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Does PhotoPrism require the cloud?$q$, $q$No, PhotoPrism is designed to be self-hosted on a user's own hardware, though managed hosting options also exist.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$What license does PhotoPrism use?$q$, $q$The PhotoPrism Community Edition is licensed under the AGPLv3.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$How is PhotoPrism different from Immich?$q$, $q$Both are open-source, self-hosted photo managers; PhotoPrism emphasizes AI search and a mature web UI, while Immich emphasizes mobile-first backup.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Can I use PhotoPrism without self-hosting?$q$, $q$Yes, via managed hosting offered by PhotoPrism itself or third parties such as PikaPods.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Private family photo library$q$, $q$Families use PhotoPrism to organize and search decades of photos and videos without uploading them to a third-party cloud service.$q$, $q$Privacy-conscious individuals and families$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Self-hosted alternative to Google Photos$q$, $q$Home lab and self-hosting enthusiasts run PhotoPrism as a privacy-respecting replacement for commercial cloud photo services.$q$, $q$Home lab and self-hosting enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Organizing large professional photo archives$q$, $q$Photographers and small studios use PhotoPrism's AI tagging and duplicate detection to manage large personal media archives.$q$, $q$Photographers and small studios$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Community Edition$q$, $q$Free$q$, $q$N/A (self-hosted)$q$, NULL, $q$["Open-source, AGPLv3 licensed","Unlimited storage on your own hardware","AI tagging, face recognition and duplicate detection","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Essentials$q$, $q$From about EUR2/month self-hosted (about EUR200/month managed)$q$, $q$Annual$q$, NULL, $q$["Additional user roles","Enhanced maps and geocoding","Private member chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$Plus$q$, $q$From about EUR6/month self-hosted (about EUR600/month managed)$q$, $q$Annual$q$, NULL, $q$["Full user-management UI","Ollama and OpenAI AI backend integrations","Single sign-on via OpenID Connect","Hardened security options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PhotoPrism is a self-hosted, open-source photo and video management application that brings AI-powered organization, tagging, face recognition and search to a user's own personal media library, without requiring uploads to a third-party cloud service. It was founded in 2018 by Michael Mayer and Theresa Gresch and is based in Berlin, Germany.$q$, $q$The company behind PhotoPrism, PhotoPrism UG, is 100 percent self-funded with a small team, which the founders present as central to their commitment to user privacy and transparency, since the business does not depend on advertising or selling user data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$PhotoPrism uses AI to automatically tag photos by content, detect and group faces, find duplicate images, and plot geotagged photos on an interactive world map, all running on infrastructure the user controls rather than a third-party cloud.$q$, $q$The software deploys via Docker on anything from a Raspberry Pi to a home server or cloud VPS, and paid memberships add optional capabilities such as a full user-management interface, integrations with AI backends like Ollama and OpenAI, and single sign-on via OpenID Connect.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core PhotoPrism Community Edition is free and open source under the AGPLv3 license, with unlimited storage limited only by a user's own hardware. Optional Essentials and Plus memberships, priced from around EUR2 and EUR6 per month respectively for self-hosted use, unlock extra features and are billed annually.$q$, $q$For users who don't want to self-host at all, PhotoPrism itself offers managed hosting from roughly EUR200 to EUR600 per month, and third-party providers such as PikaPods offer fully managed PhotoPrism instances starting around $6.50 per month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2f89cac5-124c-4e1b-8f09-b84e459dd4dc', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
